            target.textContent?.trim();
        if (!nodeId)
            return;
        // Dim all elements first
        const allElements = svg.querySelectorAll('circle, text, line, path');
        allElements.forEach(el => {
            el.style.opacity = '0.3';
            el.style.filter = 'grayscale(0.7)';
        });
